// Error categories reported through Status.ErrorCategory. Exactly one of these
// is always set.
const (
	// CategoryNone means the most recent reload attempt succeeded (or no reload
	// has happened yet).
	CategoryNone = "none"
	// CategoryLoad means loading or parsing the configuration file failed. No
	// component applied the new configuration, so no rollback is attempted.
	CategoryLoad = "load_error"
	// CategoryApply means a component failed while applying the new
	// configuration. If an earlier component had already applied it, a rollback
	// to the last known-good configuration is attempted.
	CategoryApply = "apply_error"
	// CategoryRollback means a component failed to apply the new configuration
	// and the subsequent rollback to the last known-good configuration also
	// failed, leaving the runtime in a mixed state.
	CategoryRollback = "rollback_error"
)

// StateFilename is the name of the JSON file used to persist the latest reload
// outcome under the configured TSDB storage directory.
const StateFilename = "reload_status.json"

// Status is the observable outcome of the most recent configuration reload
// attempt. Its JSON representation is both served by
// GET /api/v1/status/reload and persisted to disk.
type Status struct {
	// LastReloadID identifies the most recent reload attempt as an RFC3339
	// timestamp. It is empty when no reload has been attempted yet.
	LastReloadID string `json:"last_reload_id"`
	// LastReloadSuccessful reports whether the most recent reload attempt
	// applied the new configuration to every component.
	LastReloadSuccessful bool `json:"last_reload_successful"`
	// ErrorCategory is one of CategoryNone, CategoryLoad, CategoryApply or
	// CategoryRollback.
	ErrorCategory string `json:"error_category"`
	// ErrorMessage is a human readable description of the failure, empty on
	// success.
	ErrorMessage string `json:"error_message"`
	// AppliedReloaders lists, in order, the reloaders that successfully applied
	// the new configuration during the attempt.
	AppliedReloaders []string `json:"applied_reloaders"`
	// RollbackAttempted reports whether a rollback to the last known-good
	// configuration was attempted.
	RollbackAttempted bool `json:"rollback_attempted"`
	// RollbackSuccessful reports whether that rollback succeeded.
	RollbackSuccessful bool `json:"rollback_successful"`
	// FailedReloader is the name of the reloader that failed, empty on success.
	FailedReloader string `json:"failed_reloader"`
	// ReloaderTimingsMs maps a reloader name to the time it took to apply the
	// new configuration, in milliseconds.
	ReloaderTimingsMs map[string]float64 `json:"reloader_timings_ms"`
}

// Initial returns the Status served before the first reload attempt.
func Initial() Status {
	return Status{
		LastReloadID:      "",
		ErrorCategory:     CategoryNone,
		AppliedReloaders:  []string{},
		ReloaderTimingsMs: map[string]float64{},
	}
}

// normalize replaces nil slices/maps and an empty error category so that the
// served and persisted representations are always well formed.
func normalize(s Status) Status {
	if s.AppliedReloaders == nil {
		s.AppliedReloaders = []string{}
	}
	if s.ReloaderTimingsMs == nil {
		s.ReloaderTimingsMs = map[string]float64{}
	}
	if s.ErrorCategory == "" {
		s.ErrorCategory = CategoryNone
	}
	return s
}

