// reloadConfigTransactional applies a new configuration through the reloaders in
// sequence, recording a single outcome for the whole attempt. If a component
// fails after an earlier component has already applied the new configuration,
// it rolls back every reloader to the last known-good configuration.
func reloadConfigTransactional(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rt *reloadTracker, record bool, rls []reloader) (err error) {
	start := time.Now()
	logger.Info("Loading configuration file", "filename", filename)

	status := reloadstatus.Status{
		LastReloadID:      start.Format(time.RFC3339),
		ErrorCategory:     reloadstatus.CategoryNone,
		AppliedReloaders:  []string{},
		ReloaderTimingsMs: map[string]float64{},
	}

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			configSuccess.Set(0)
			callback(false)
		}
		// The initial startup load establishes the first known-good
		// configuration but does not count as a reload attempt, so its outcome
		// is neither recorded nor persisted.
		if record && rt.status != nil {
			rt.status.Set(status)
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		status.LastReloadSuccessful = false
		status.ErrorCategory = reloadstatus.CategoryLoad
		status.ErrorMessage = err.Error()
		// A load or parse failure means no component applied anything, so there
		// is nothing to roll back.
		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
	}

	if enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	for _, rl := range rls {
		rstart := time.Now()
		rerr := rl.reloader(conf)
		status.ReloaderTimingsMs[rl.name] = float64(time.Since(rstart).Nanoseconds()) / 1e6
		if rerr != nil {
			logger.Error("Failed to apply configuration", "reloader", rl.name, "err", rerr)
			status.LastReloadSuccessful = false
			status.ErrorCategory = reloadstatus.CategoryApply
			status.ErrorMessage = rerr.Error()
			status.FailedReloader = rl.name

			// Roll back only when an earlier component already applied the new
			// configuration and we have a known-good configuration to restore.
			lastGood := rt.getLastGood()
			if len(status.AppliedReloaders) > 0 && lastGood != nil {
				status.RollbackAttempted = true
				if rollbackErr := runRollback(lastGood, rls, logger); rollbackErr != nil {
					status.RollbackSuccessful = false
					status.ErrorCategory = reloadstatus.CategoryRollback
					status.ErrorMessage = fmt.Sprintf("%s; rollback failed: %s", rerr.Error(), rollbackErr.Error())
					logger.Error("Rollback to last known-good configuration failed", "err", rollbackErr)
				} else {
					status.RollbackSuccessful = true
					logger.Info("Rolled back to last known-good configuration")
				}
			}
			return fmt.Errorf("error applying the new configuration in reloader %q (--config.file=%q): %w", rl.name, filename, rerr)
		}
		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
	}

	status.LastReloadSuccessful = true
	status.ErrorCategory = reloadstatus.CategoryNone
	rt.setLastGood(conf)

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
}

// runRollback re-applies conf through every reloader, returning an error if any
// reloader fails. It is used to restore the last known-good configuration after
// a partially-applied reload.
func runRollback(conf *config.Config, rls []reloader, logger *slog.Logger) error {
	var errs []error
	for _, rl := range rls {
		if err := rl.reloader(conf); err != nil {
			logger.Error("Failed to roll back configuration", "reloader", rl.name, "err", err)
			errs = append(errs, fmt.Errorf("%s: %w", rl.name, err))
		}
	}
	return errors.Join(errs...)
}

