package reloadstatus

import (
	"os"
	"path/filepath"
	"testing"

	"github.com/stretchr/testify/require"
)

func TestInitialStatus(t *testing.T) {
	dir := t.TempDir()
	tr := NewTracker(dir, nil)

	got := tr.Get()
	require.Equal(t, "", got.LastReloadID)
	require.False(t, got.LastReloadSuccessful)
	require.Equal(t, CategoryNone, got.ErrorCategory)
	require.Equal(t, []string{}, got.AppliedReloaders)
	require.Equal(t, map[string]float64{}, got.ReloaderTimingsMs)
	require.False(t, got.RollbackAttempted)

	// No state file must be written before the first Set.
	_, err := os.Stat(filepath.Join(dir, StateFilename))
	require.True(t, os.IsNotExist(err), "state file should not exist before first reload")
}

func TestSetPersistsAndReloads(t *testing.T) {
	dir := t.TempDir()
	tr := NewTracker(dir, nil)

	want := Status{
		LastReloadID:         "2026-07-14T10:00:00Z",
		LastReloadSuccessful: false,
		ErrorCategory:        CategoryApply,
		ErrorMessage:         "boom",
		AppliedReloaders:     []string{"db_storage", "remote_storage"},
		RollbackAttempted:    true,
		RollbackSuccessful:   true,
		FailedReloader:       "scrape",
		ReloaderTimingsMs:    map[string]float64{"db_storage": 1.5, "scrape": 2.0},
	}
	tr.Set(want)

	// State file is written.
	require.FileExists(t, filepath.Join(dir, StateFilename))

	// A new tracker over the same directory recovers the persisted state,
	// simulating a restart.
	restarted := NewTracker(dir, nil)
	require.Equal(t, want, restarted.Get())
}

func TestSetNormalizesNilCollections(t *testing.T) {
	dir := t.TempDir()
	tr := NewTracker(dir, nil)

	tr.Set(Status{LastReloadID: "id"})
	got := tr.Get()
	require.Equal(t, []string{}, got.AppliedReloaders)
	require.Equal(t, map[string]float64{}, got.ReloaderTimingsMs)
	require.Equal(t, CategoryNone, got.ErrorCategory)
}

func TestCorruptedStateFileIgnored(t *testing.T) {
	dir := t.TempDir()
	require.NoError(t, os.WriteFile(filepath.Join(dir, StateFilename), []byte("{not valid json"), 0o644))

	// Must not panic or error; falls back to the initial status.
	tr := NewTracker(dir, nil)
	require.Equal(t, Initial(), tr.Get())
}

