const minimalConfig = "global: {}\n"

// applied records, in order, which reloaders ran and with which scrape interval
// so a test can assert that a rollback restored the previous configuration.
type applied struct {
	names []string
}

// okReloader returns a reloader that records that it ran.
func okReloader(name string, a *applied) reloader {
	return reloader{
		name: name,
		reloader: func(*config.Config) error {
			a.names = append(a.names, name)
			return nil
		},
	}
}

// failReloader returns a reloader that always fails.
func failReloader(name string) reloader {
	return reloader{
		name: name,
		reloader: func(*config.Config) error {
			return errors.New("boom in " + name)
		},
	}
}

func writeConfig(t *testing.T, content string) string {
	t.Helper()
	dir := t.TempDir()
	path := filepath.Join(dir, "prometheus.yml")
	require.NoError(t, os.WriteFile(path, []byte(content), 0o644))
	return path
}

func newTransactionalTracker(t *testing.T) *reloadTracker {
	t.Helper()
	return &reloadTracker{
		enabled: true,
		status:  reloadstatus.NewTracker(t.TempDir(), promslog.NewNopLogger()),
	}
}

func TestTransactionalReload_Success(t *testing.T) {
	cfgFile := writeConfig(t, minimalConfig)
	rt := newTransactionalTracker(t)
	logger := promslog.NewNopLogger()
	noStep := &safePromQLNoStepSubqueryInterval{}
	var a applied

	err := reloadConfig(cfgFile, false, logger, noStep, func(bool) {}, rt, true,
		okReloader("db_storage", &a), okReloader("scrape", &a))
	require.NoError(t, err)

	st := rt.status.Get()
	require.True(t, st.LastReloadSuccessful)
	require.Equal(t, reloadstatus.CategoryNone, st.ErrorCategory)
	require.Equal(t, []string{"db_storage", "scrape"}, st.AppliedReloaders)
	require.False(t, st.RollbackAttempted)
	require.NotEmpty(t, st.LastReloadID)
	require.Contains(t, st.ReloaderTimingsMs, "db_storage")
	require.Contains(t, st.ReloaderTimingsMs, "scrape")
	require.NotNil(t, rt.getLastGood(), "successful reload must establish a known-good config")
}

func TestTransactionalReload_LoadErrorNoRollback(t *testing.T) {
	cfgFile := writeConfig(t, minimalConfig)
	rt := newTransactionalTracker(t)
	// Establish a known-good config first.
	require.NoError(t, reloadConfig(cfgFile, false, promslog.NewNopLogger(), &safePromQLNoStepSubqueryInterval{}, func(bool) {}, rt, true, okReloader("db_storage", &applied{})))

	badFile := writeConfig(t, "global: {\n  bad yaml")
	var a applied
	err := reloadConfig(badFile, false, promslog.NewNopLogger(), &safePromQLNoStepSubqueryInterval{}, func(bool) {}, rt, true, okReloader("db_storage", &a))
	require.Error(t, err)

	st := rt.status.Get()
	require.False(t, st.LastReloadSuccessful)
	require.Equal(t, reloadstatus.CategoryLoad, st.ErrorCategory)
	require.False(t, st.RollbackAttempted, "load errors must not trigger a rollback")
	require.Empty(t, a.names, "no reloader should run when config fails to load")
}

func TestTransactionalReload_FirstReloaderFailsNoRollback(t *testing.T) {
	cfgFile := writeConfig(t, minimalConfig)
	rt := newTransactionalTracker(t)
	require.NoError(t, reloadConfig(cfgFile, false, promslog.NewNopLogger(), &safePromQLNoStepSubqueryInterval{}, func(bool) {}, rt, true, okReloader("db_storage", &applied{})))

	err := reloadConfig(cfgFile, false, promslog.NewNopLogger(), &safePromQLNoStepSubqueryInterval{}, func(bool) {}, rt, true,
		failReloader("db_storage"), okReloader("scrape", &applied{}))
	require.Error(t, err)

	st := rt.status.Get()
	require.Equal(t, reloadstatus.CategoryApply, st.ErrorCategory)
	require.Equal(t, "db_storage", st.FailedReloader)
	require.Empty(t, st.AppliedReloaders)
	require.False(t, st.RollbackAttempted, "nothing applied yet, so no rollback")
}

